const aiText = $input.first().json?.message?.content ?? $input.first().json?.text ?? '[]';
let results = [];
try {
  const cleaned = aiText.replace(/```json|```/g, '').trim();
  results = JSON.parse(cleaned);
  if (!Array.isArray(results)) results = [];
} catch(e) {
  results = [];
}
return [{ json: { success: true, data: results, count: results.length, op: 'ai_search' } }];
